#include <bits/stdc++.h>
using namespace std;

const int N=2e5+10,INF=1e9;

struct Node{
    int s[2],v,f,sz;
    int ms,ls,rs,sum;
    int rev,cov;
    void init(int _v,int _f){
        s[0]=s[1]=0,v=_v,f=_f,sz=1;
        ms=sum=v,ls=rs=max(0,v);
        rev=cov=0;
    }
}t[N];

int n,m,stk[N],top;
int root,w[N];

void pushup(int x){
    auto &u=t[x],&l=t[t[x].s[0]],&r=t[t[x].s[1]];
    u.sz=l.sz+1+r.sz;
    u.sum=l.sum+u.v+r.sum;
    u.ls=max(l.ls,l.sum+u.v+r.ls);
    u.rs=max(r.rs,r.sum+u.v+l.rs);
    u.ms=max(max(l.ms,r.ms),l.rs+u.v+r.ls);
}

void pushdown(int x){
    auto &u=t[x],&l=t[t[x].s[0]],&r=t[t[x].s[1]];
    if(u.cov){
        u.cov=u.rev=0;
        if(u.s[0]) l.cov=1,l.v=u.v,l.sum=l.sz*u.v;
        if(u.s[1]) r.cov=1,r.v=u.v,r.sum=r.sz*u.v;
        if(u.v>0){
            if(u.s[0]) l.ms=l.ls=l.rs=l.sum;
            if(u.s[1]) r.ms=r.ls=r.rs=r.sum;
        }else{
            if(u.s[0]) l.ms=u.v,l.ls=l.rs=0;
            if(u.s[1]) r.ms=u.v,r.ls=r.rs=0;
        }
    }
    if(u.rev){
        u.rev=0;
        if(u.s[0]){
            l.rev^=1;
            swap(l.ls,l.rs);
            swap(l.s[0],l.s[1]);
        }
        if(u.s[1]){
            r.rev^=1;
            swap(r.ls,r.rs);
            swap(r.s[0],r.s[1]);
        }
    }
}

int build(int l,int r,int f){
    if(l>r) return 0;
    int mid=l+r>>1,u=stk[top--];
    t[u].init(w[mid],f);
    if(l<mid) t[u].s[0]=build(l,mid-1,u);
    if(r>mid) t[u].s[1]=build(mid+1,r,u);
    pushup(u);
    return u;
}

void dfs(int u){
    if(t[u].s[0]) dfs(t[u].s[0]);
    if(t[u].s[1]) dfs(t[u].s[1]);
    stk[++top]=u;
}

void Rotate(int x){
    int y=t[x].f,z=t[y].f,k=(x==t[y].s[1]);
    t[z].s[y==t[z].s[1]]=x,t[x].f=z;
    t[y].s[k]=t[x].s[k^1],t[t[x].s[k^1]].f=y;
    t[x].s[k^1]=y,t[y].f=x;
    pushup(y),pushup(x);
}

void Splay(int x,int k){
    while(t[x].f!=k){
        int y=t[x].f,z=t[y].f;
        if(z!=k)
            if((x==t[y].s[1])^(y==t[z].s[1])) Rotate(x);
            else Rotate(y);
        Rotate(x);
    }
    if(!k) root=x;
}

int get_k(int k){
    int u=root;
    while(u){
        pushdown(u);
        if(t[t[u].s[0]].sz>=k) u=t[u].s[0];
        else if(t[t[u].s[0]].sz+1==k) return u;
        else k-=t[t[u].s[0]].sz+1,u=t[u].s[1];
    }
    return -1;
}

int main(){
    for(int i=1;i<N;i++) stk[++top]=i;

    scanf("%d%d",&n,&m);
    t[0].ms=w[0]=w[n+1]=-INF;
    for(int i=1;i<=n;i++)
        scanf("%d",&w[i]);
    root=build(0,n+1,0);

    while(m--){
        char op[15];
        scanf("%s",op);
        if(!strcmp(op,"INSERT")){
            int posi,tot;
            scanf("%d%d",&posi,&tot);
            for(int i=0;i<tot;i++)
                scanf("%d",&w[i]);

            int l=get_k(posi+1),r=get_k(posi+2);
            Splay(l,0),Splay(r,l);
            t[r].s[0]=build(0,tot-1,r);
            pushup(r),pushup(l);
        }else if(!strcmp(op,"DELETE")){
            int posi,tot;
            scanf("%d%d",&posi,&tot);

            int l=get_k(posi),r=get_k(posi+tot+1);
            Splay(l,0),Splay(r,l);
            dfs(t[r].s[0]);
            t[r].s[0]=0;
            pushup(r),pushup(l);
        }else if(!strcmp(op,"MAKE-SAME")){
            int posi,tot,c;
            scanf("%d%d%d",&posi,&tot,&c);

            int l=get_k(posi),r=get_k(posi+tot+1);
            Splay(l,0),Splay(r,l);
            auto &u=t[t[r].s[0]];
            u.cov=1,u.v=c,u.sum=c*u.sz;
            if(c>0) u.ms=u.ls=u.rs=u.sum;
            else u.ms=c,u.ls=u.rs=0;
            pushup(r),pushup(l);
        }else if(!strcmp(op,"REVERSE")){
            int posi,tot;
            scanf("%d%d",&posi,&tot);

            int l=get_k(posi),r=get_k(posi+tot+1);
            Splay(l,0),Splay(r,l);
            auto &u=t[t[r].s[0]];
            u.rev^=1;
            swap(u.ls,u.rs);
            swap(u.s[0],u.s[1]);
            pushup(r),pushup(l);
        }else if(!strcmp(op,"GET-SUM")){
            int posi,tot;
            scanf("%d%d",&posi,&tot);

            int l=get_k(posi),r=get_k(posi+tot+1);
            Splay(l,0),Splay(r,l);
            printf("%d\n",t[t[r].s[0]].sum);
        }else if(!strcmp(op,"GET")){
            int posi;
            scanf("%d",&posi);
            int x=get_k(posi+1);
            Splay(x,0);
            printf("%d\n",t[x].v);
        }else{
            int posi,tot;
            scanf("%d%d",&posi,&tot);

            int l=get_k(posi),r=get_k(posi+tot+1);
            Splay(l,0),Splay(r,l);
            printf("%d\n",t[t[r].s[0]].ms);
        }
    }
    return 0;
}
